// Compute one-way distance from Stratford City Hall and travel fee
const origin = { lat: 43.3700, lng: -80.9821 };
const geo = $input.first().json.results?.[0]?.geometry?.location;
const lead = $('Normalize Lead').first().json;

function haversine(a, b) {
  const R = 6371;
  const dLat = (b.lat - a.lat) * Math.PI / 180;
  const dLng = (b.lng - a.lng) * Math.PI / 180;
  const x = Math.sin(dLat/2)**2 + Math.cos(a.lat*Math.PI/180) * Math.cos(b.lat*Math.PI/180) * Math.sin(dLng/2)**2;
  return 2 * R * Math.asin(Math.sqrt(x));
}

let one_way_km = 0;
let geocode_ok = false;
if (geo) {
  one_way_km = Math.round(haversine(origin, geo) * 10) / 10;
  geocode_ok = true;
}

const FREE_KM = 5;
const MIN_FEE = 20;
const PER_KM = 1.0;
const AUTO_MAX = 30;
const HARD_CAP = 45;

let travel_fee = 0;
let decision_path = 'auto_book';
let decision_reason = 'in_zone';

if (!geocode_ok) {
  decision_path = 'owner_review';
  decision_reason = 'geocode_failed';
} else if (one_way_km <= FREE_KM) {
  travel_fee = 0;
} else if (one_way_km > HARD_CAP) {
  decision_path = 'auto_decline';
  decision_reason = 'out_of_service_area';
} else {
  const billable = (one_way_km * 2) - (FREE_KM * 2);
  travel_fee = Math.max(MIN_FEE, Math.round(billable * PER_KM));
  if (one_way_km > AUTO_MAX) {
    decision_path = 'owner_review';
    decision_reason = 'out_of_area_review';
  }
}

return [{
  json: {
    ...lead,
    geocode_ok,
    one_way_km,
    travel_fee,
    decision_path,
    decision_reason,
    coords: geo || null
  }
}];

// Compute available slots: 7am–9pm America/Toronto, 8hr crew cap, 30min buffer
const events = $input.all().map(i => i.json);
const lead = $('Compute Distance & Travel Fee').first().json;

const tz = 'America/Toronto';
const now = new Date();
const openHour = 7;
const closeHour = 21;
const dayCapHours = 8;
const bufferMin = 30;

const byDay = {};
for (const e of events) {
  if (!e.start || !e.end) continue;
  const d = new Date(e.start.dateTime || e.start.date).toISOString().slice(0,10);
  const len = (new Date(e.end.dateTime) - new Date(e.start.dateTime)) / 3600000;
  byDay[d] = (byDay[d] || 0) + len;
}

const slots = [];
for (let i = 1; i <= 7 && slots.length < 6; i++) {
  const d = new Date(now);
  d.setDate(d.getDate() + i);
  const dayKey = d.toISOString().slice(0,10);
  const used = byDay[dayKey] || 0;
  if (used >= dayCapHours) continue;
  // propose 9am and 1pm slots if room
  for (const startH of [9, 13]) {
    if (slots.length >= 6) break;
    const startISO = `${dayKey}T${String(startH).padStart(2,'0')}:00:00-04:00`;
    slots.push({ start_iso: startISO, day_used_hr: used });
  }
}

return [{ json: { ...lead, available_slots: slots } }];

// Parse the AI's structured JSON output
const raw = $input.first().json.output || $input.first().json.text || '';
const match = raw.match(/\{[\s\S]*\}/);
if (!match) throw new Error('AI did not return JSON: ' + raw.slice(0, 200));
const quote = JSON.parse(match[0]);
return [{ json: quote }];

// Send each AI-generated SMS message as a separate Twilio call (multi-text feel)
const quote = $input.first().json;
const items = (quote.messages || []).map((body, i) => ({
  json: {
    to: quote.customer.phone_e164,
    body,
    delay_ms: i * 1500,  // 1.5s between texts
    quote_ref: quote
  }
}));
return items;

// Build the Square booking link with prefilled service + customer data
const q = $input.first().json;
const params = new URLSearchParams({
  customer_name: `${q.customer.first_name} `,
  customer_phone: q.customer.phone_e164,
  service_ids: q.services.map(s => s.id).join(','),
  total: q.totals.total,
  deposit: q.totals.deposit_amount
});
return [{ json: { booking_url: `https://app.squareup.com/appointments/book/premier-detailing?${params.toString()}` } }];

